void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 c = (vUv-0.5)*uAspect.xy;
float z = 0.4;
polar = vec2( atan(c.x,z), atan(c.y,z));
vec3 p = vec3( sin(polar.x)*cos(polar.y),sin(polar.y)*cos(polar.x),cos(polar.x)*cos(polar.y));
factorA = p.zy;factorB = vec2(q2,q3);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zy = product.xy;factorA = p.zx;factorB = vec2(q4,q5);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zx = product.xy;factorA = p.yx;factorB = vec2(q6,q7);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
p.yx = product.xy;polar = vec2( atan(p.x,p.z)*q1,atan(p.y,length(p.xz))*q1*2 + 0.5);
ret = tex2d(sampler_rand00,0.5 + (polar-0.5));

ret = mix(ret,1-ret,GetPixel(vUv));


